#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1e5+5;
struct node{int x,y,id;}a[N];
struct DDD{
    int mx;LD lv;
}dp[N],f[N],g[N],h[N],c[N],Ans;
bool cmp1(node A,node B){return A.x>B.x;}
bool cmp2(node A,node B){return A.id<B.id;}
DDD operator + (const DDD &A , const DDD &B){
    DDD res={0,0};res.mx=max(A.mx,B.mx);
    if(res.mx==A.mx)res.lv+=A.lv;
    if(res.mx==B.mx)res.lv+=B.lv;return res;
}int n,Tw;map<int,int> Ls;
void upd(int x,DDD k){while(x)c[x]=c[x]+k,x-=x&-x;return;}
DDD ask(int x){DDD sum={0,0};while(x<=Tw)sum=sum+c[x],x+=x&-x;return sum;}
void clr(int x){while(x)c[x]={0,0},x-=x&-x;return;}
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void CDQsolve(int l,int r){
    if(l==r){dp[a[l].id]=dp[a[l].id]+DDD{1,1};return;}
    int mid=(l+r)>>1;CDQsolve(l,mid);
    sort(a+l,a+mid+1,cmp1);
    sort(a+mid+1,a+r+1,cmp1);
    int pl=l,pr=mid+1;
    while(pr<=r){
        while(pl<=mid&&a[pl].x>=a[pr].x)
            upd(a[pl].y,dp[a[pl].id]),pl++;
        DDD tmp=ask(a[pr].y);tmp.mx++;
        dp[a[pr].id]=dp[a[pr].id]+tmp;pr++;
    }for(int i=l;i<pl;i++)clr(a[i].y);
    sort(a+mid+1,a+r+1,cmp2);
    CDQsolve(mid+1,r);return;
}
int main(){
    n=read();
    for(int i=1;i<=n;i++)
        a[i].x=read(),a[i].y=read(),
        a[i].id=i,Ls[a[i].y]=0;
    for(auto &x:Ls)x.se=(++Tw);
    for(int i=1;i<=n;i++)a[i].y=Ls[a[i].y];
    CDQsolve(1,n);
    for(int i=1;i<=n;i++)Ans=Ans+dp[i],f[i]=dp[i];
    for(int i=1;i<=n;i++)
        dp[i]={0,0},a[i].id=n-a[i].id+1,
        a[i].x=-a[i].x,a[i].y=Tw-a[i].y+1;
    sort(a+1,a+n+1,cmp2);
    CDQsolve(1,n);reverse(dp+1,dp+n+1);
    cout<<Ans.mx<<"\n";
    for(int i=1;i<=n;i++)
        if(dp[i].mx+f[i].mx-1!=Ans.mx)cout<<"0.00000 ";
        else printf("%.6Lf ",dp[i].lv*f[i].lv/Ans.lv);
    return 0;
}
